#include <iostream>
#include <fstream>
#include <string>
#include <iomanip>
#include <vector>
#include <algorithm>
#include <set>

using namespace std;

#define MAX_LETTERS 26

class Solution {
 public:
	void run() {
		read();
		write();
	}

 private:
	ifstream fin;
	ofstream fout;
	int n;
	vector<string> words;
	vector<bool> letters = vector<bool>(MAX_LETTERS, false);

	void read() {
		fin.open("criptat.in");
		fin >> n;

		for (int i = 0; i < n; i++) {
			string word;
			fin >> word;
			words.push_back(word);
			for (auto& letter : word)
				letters[letter - 'a'] = true;
		}

		fin.close();
	}

	void write() {
		fout.open("criptat.out");
		fout << solve() << '\n';
		fout.close();
	}

	int solve() {
		int result = 0;

		for (int i = 0; i < MAX_LETTERS; i++) {
			if (letters[i]) {
				char letter = 'a' + i;
				result = max(result, max_len_for_letter(words, letter));
			}
		}

		return result;
	}

	int max_len_for_letter(vector<string>& words, char letter) {
		vector<pair<int, int>> word_data;
		int total_len = 0;
		for (auto& word : words) {
			int len = word.length();
			int freq = count(word.begin(), word.end(), letter);
			word_data.push_back({len, freq});
			total_len += len;
		}

		vector<vector<int>> dp(words.size() + 1,
							   vector<int>(total_len + 1, 0));

		int word_size = words.size();
		for (int i = 1; i <= word_size; i++) {
			for (int j = 0; j <= total_len; j++) {
				dp[i][j] = dp[i - 1][j];
				int word_len = word_data[i - 1].first;
				int letter_freq = word_data[i - 1].second;
				int other_letters_len = word_len - letter_freq;

				if (j - other_letters_len >= 0) {
					int sol_aux = dp[i - 1][j - other_letters_len] + word_len;
					dp[i][j] = max(dp[i][j], sol_aux);
				}
			}
		}

		int res = 0;
		int size = dp.size() - 1;
		for (int j = 0; j <= total_len; j++)
			if (dp[size][j] > res && dp[size][j] - j > j)
				res = dp[size][j];

		return res;
	}
};

int main() {
	Solution *sol = new Solution();
	sol->run();
	delete sol;
	return 0;
}

import java.io.FileReader;
import java.io.FileWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.HashSet;
import java.util.List;
import java.util.Set;


class EncryptionSolver implements AlgorithmSolver {
	private final String inputFile = "criptat.in";
	private final String outputFile = "criptat.out";

	private List<String> words;
	private Set<Character> alphabet =  new HashSet<Character>();
	private final int maxAlphabetSize = 8;
	private int n;

	private int maxLength = -1;

	@Override
	public void read() {
		try {
			FileReader fileReader = new FileReader(inputFile);
			MyScanner scanner = new MyScanner(fileReader);
			n = scanner.nextInt();
			words = new ArrayList<String>(n);

			for (var i = 0; i < n; i++) {
				var word = scanner.next();
				words.add(word);
				// as we read the words, we add the characters to the alphabet
				if (alphabet.size() >= maxAlphabetSize) {
					continue;
				}
				word.chars().forEach(c -> alphabet.add((char) c));
			}

			fileReader.close();
		} catch (Exception e) {
			e.printStackTrace();
		}
	}

	public int maxPasswordLength(char targetChar) {
		int totalFiller = 0;
		for (String word : words) {
			int targetCount = (int) word.chars().filter(c -> c == targetChar).count();
			totalFiller += word.length() - targetCount;
		}

		// it can be done with dp[n+1][totalLength + 1],
		// but we can optimize it to dp[n+1][totalFiller + 1]
		int[][] dp = new int[n + 1][totalFiller + 1];
		// dp[i][j] = max length of password using the first i words and j filler characters
		// dp[0]  = 0, since we use no words


		for (int i = 1; i <= n; i++) {
			String word = words.get(i - 1);
			int targetCount = (int) word.chars().filter(c -> c == targetChar).count();
			int fillerCount = word.length() - targetCount;

			for (int j = 0; j <= totalFiller; j++) {
				// we do not use the current word
				dp[i][j] = dp[i - 1][j];

				if (j >= fillerCount) {
					dp[i][j] = Math.max(dp[i][j], dp[i - 1][j - fillerCount] + word.length());
				}
			}
		}

		int maxLen = 0;
		for (int j = 0; j <= totalFiller; j++) {
			if (2 * (dp[n][j] - j) > dp[n][j]) {
				maxLen = Math.max(maxLen, dp[n][j]);
			}
		}

		return maxLen;
	}


	@Override
	public void solve() {
		List<Integer> lengths = new ArrayList<Integer>();
		for (var c : alphabet) {
			lengths.add(maxPasswordLength(c));
		}

		maxLength = Collections.max(lengths);
	}

	@Override
	public void write() {
		try {
			FileWriter fileWriter = new FileWriter(outputFile);
			fileWriter.write(String.valueOf(maxLength));
			fileWriter.close();
		} catch (Exception e) {
			e.printStackTrace();
		}
	}
}

public class Criptat {
	public static void main(String[] args) {
		AlgorithmSolver solver = new EncryptionSolver();
		solver.read();
		solver.solve();
		solver.write();
	}
}
